class Solution:
    def countSubstrings(self, s: str) -> int:
        n = len(s)
        total = 0
        for i in range(n):
            for j in range(i, n):
                d = int(s[j])
                if d == 0:
                    continue
                if int(s[i:j+1]) % d == 0:
                    total += 1
        return total

