class Solution:
    def countSubstrings(self, s: str) -> int:
        n = len(s)
        cnt = [None] + [[0] * d for d in range(1, 10)]
        total = 0
        for ch in s:
            digit = int(ch)
            for d in range(1, 10):
                old = cnt[d]
                new = [0] * d
                for r in range(d):
                    c = old[r]
                    if c:
                        nr = (r * 10 + digit) % d
                        new[nr] += c
                new[digit % d] += 1
                cnt[d] = new
            if digit != 0:
                total += cnt[digit][0]
        return total

