var countSubstrings = function(s) {
    let cnt = [null];
    for (let d = 1; d <= 9; d++) cnt.push(new Array(d).fill(0));
    let total = 0;
    for (let idx = 0; idx < s.length; idx++) {
        const digit = s.charCodeAt(idx) - 48;
        for (let d = 1; d <= 9; d++) {
            const old = cnt[d];
            const fresh = new Array(d).fill(0);
            for (let r = 0; r < d; r++) {
                const c = old[r];
                if (c) {
                    const nr = (r * 10 + digit) % d;
                    fresh[nr] += c;
                }
            }
            fresh[digit % d] += 1;
            cnt[d] = fresh;
        }
        if (digit !== 0) total += cnt[digit][0];
    }
    return total;
};
